Action: WriteFileTool(WriteFileTool { path: "src/lib/comfort-index.ts", content: "import { SubScore } from '../types';

export const calculateComfortIndex = (scores: SubScore[]): number => {
  const totalWeight = scores.reduce((sum, s) => sum + s.weight, 0);
  const weightedSum = scores.reduce((sum, s) => sum + (s.normalized * s.weight), 0);
  return totalWeight > 0 ? weightedSum / totalWeight : 0;
};
" })

