import { fetchOpenMeteo } from '../apis/open-meteo';

export const airModule: DataModule = {
  name: 'Air Quality',
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('air-quality', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      current: 'pm2_5',
    });
    return { raw: data, score: this.normalize(data.current.pm2_5) };
  },
  normalize(pm25: number) {
    // Simple AQI PM2.5 normalization: 0-12=1.0, 12-35=0.7, >35=0.3
    if (pm25 <= 12) return 1.0;
    if (pm25 <= 35) return 0.7;
    return 0.3;
  }
};
" })

