import { fetchOpenMeteo } from '../apis/open-meteo';

export const weatherModule: DataModule = {
  name: 'Weather',
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('forecast', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      current: 'temperature_2m,relative_humidity_2m,wind_speed_10m,surface_pressure',
    });
    return { raw: data, score: this.normalize(data.current) };
  },
  normalize(data: any) {
    // Simple temperature-based comfort (assuming 22C is ideal)
    const temp = data.temperature_2m;
    const diff = Math.abs(temp - 22);
    return Math.max(0, 1 - (diff / 20));
  }
};
" })

