import { fetchOpenMeteo } from '../apis/open-meteo';

export const uvModule: DataModule = {
  name: 'UV Index',
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('forecast', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      hourly: 'uv_index',
    });
    // Using current or first hour index
    const uv = data.hourly.uv_index[0] || 0;
    return { raw: data, score: this.normalize(uv) };
  },
  normalize(uv: number) {
    // UV Index: 0-2=1.0, 3-5=0.7, 6-7=0.4, 8+=0.1
    if (uv <= 2) return 1.0;
    if (uv <= 5) return 0.7;
    if (uv <= 7) return 0.4;
    return 0.1;
  }
};
" })

