Action: WriteFileTool(WriteFileTool { path: "src/lib/modules/earthquake.ts", content: "import { DataModule } from '../../types';

export const earthquakeModule: DataModule = {
  name: 'Earthquake',
  async fetch(lat, lon) {
    // USGS GeoJSON API
    const url = `https://earthquake.usgs.gov/fdsnws/event/1/query?format=geojson&latitude=${lat}&longitude=${lon}&maxradiuskm=500&limit=1`;
    const response = await fetch(url);
    const data = await response.json();
    return { raw: data, score: this.normalize(data) };
  },
  normalize(data: any) {
    if (!data.features || data.features.length === 0) return 1.0;
    const mag = data.features[0].properties.mag;
    // Simple magnitude normalization: < 3.0=1.0, 3-5=0.5, > 5=0.0
    if (mag < 3) return 1.0;
    if (mag < 5) return 0.5;
    return 0.0;
  }
};
" })

