import { fetchOpenMeteo } from '../apis/open-meteo';

export const marineModule: DataModule = {
  name: 'Marine',
  async fetch(lat, lon) {
    const data = await fetchOpenMeteo('marine', {
      latitude: lat.toString(),
      longitude: lon.toString(),
      current: 'wave_height,water_temperature',
    });
    return { raw: data, score: this.normalize(data.current) };
  },
  normalize(data: any) {
    const waveHeight = data.wave_height || 0;
    // Simple wave height comfort: 0-1m=1.0, 1-2m=0.6, >2m=0.2
    if (waveHeight <= 1) return 1.0;
    if (waveHeight <= 2) return 0.6;
    return 0.2;
  }
};
" })

